from collections import Counter

def top_char(s):
    counts = Counter(s)
    return max(s, key=lambda c: counts[c])

from collections import defaultdict

def group_by_len(words):
    groups = defaultdict(list)
    for w in words:
        groups[len(w)].append(w)
    return dict(groups)

tests:
assert group_by_len(['a', 'bb', 'cc', 'd']) == {1: ['a', 'd'], 2: ['bb', 'cc']}
assert group_by_len([]) == {}
assert group_by_len(['xyz']) == {3: ['xyz']}
